import json,sys,urllib.request,urllib.error,time,base64
K=sys.argv[1]; WF=base64.b64decode(sys.argv[2]).decode('utf-8'); B='https://irynakarmazina.app.n8n.cloud/api/v1/'
def call(method,u,data=None):
    h={'X-N8N-API-KEY':K}
    if data is not None: h['Content-Type']='application/json'
    for a in range(6):
        try:
            r=urllib.request.urlopen(urllib.request.Request(B+u,data=data,method=method,headers=h),timeout=25); return r.status,r.read()
        except urllib.error.HTTPError as e: return e.code,e.read()
        except Exception: time.sleep(3)
    return None,b''
st,body=call('POST','workflows',WF.encode('utf-8'))
if st not in (200,201): print('CREATE fail',st,body[:300]); sys.exit()
wid=json.loads(body).get('id'); print('created',wid)
call('POST','workflows/'+wid+'/activate'); time.sleep(4)
import urllib.request as U
try:
    r=U.urlopen(U.Request('https://irynakarmazina.app.n8n.cloud/webhook/claude-status-dv',data=b'{}',method='POST',headers={'Content-Type':'application/json'}),timeout=60)
    print('RESULT:',r.read().decode('utf-8','ignore')[:600])
except Exception as e: print('webhook err',e)
call('DELETE','workflows/'+wid); print('deleted')

PYEOF
